  const [conversationEntities, projects, recentDecisions, openQuestions, openObservations, onboardingSummary, queryEmbedding] = await Promise.all([
    loaders.listConversationEntities({
      surreal: input.surreal,
      conversationRecord: input.conversationRecord,
      workspaceRecord: input.workspaceRecord,
      limit: 60,
