 57→    listWorkspaceRecentDecisions,
 58→    listWorkspaceOpenQuestions,
 59→    listWorkspaceOpenObservations,
 60→    loadOnboardingSummary,
 61→  };
 62→
 63→  const [conversationEntities, projects, recentDecisions, openQuestions, openObservations, onboardingSummary] = await Promise.all([
 64→    loaders.listConversationEntities({
 65→      surreal: input.surreal,
 66→      conversationRecord: input.conversationRecord,
 67→      workspaceRecord: input.workspaceRecord,
 68→      limit: 60,
 69→      ...(input.inheritedEntityIds && input.inheritedEntityIds.length > 0
 70→        ? { inheritedEntityIds: input.inheritedEntityIds }
 71→        : {}),
 72→    }),
 73→    loaders.listWorkspaceProjectSummaries({
 74→      surreal: input.surreal,
 75→      workspaceRecord: input.workspaceRecord,
 76→      limit: 20,
 77→    }),
 78→    loaders.listWorkspaceRecentDecisions({
 79→      surreal: input.surreal,
 80→      workspaceRecord: input.workspaceRecord,
 81→      limit: 12,
 82→    }),
 83→    loaders.listWorkspaceOpenQuestions({
 84→      surreal: input.surreal,
 85→      workspaceRecord: input.workspaceRecord,
 86→      limit: 12,
 87→    }),
 88→    loaders.listWorkspaceOpenObservations({
 89→      surreal: input.surreal,
 90→      workspaceRecord: input.workspaceRecord,
 91→      limit: 10,
 92→    }),
 93→    loaders.loadOnboardingSummary(input.surreal, input.workspaceRecord),
 94→  ]);
 95→
 96→  let discussedEntity: DiscussedEntityContext | undefined;
 97→  if (input.discussesRecord) {
 98→    const entityRecord = input.discussesRecord as GraphEntityRecord;
 99→    const name = await readEntityName(input.surreal, entityRecord);
100→    if (name) {
101→      const row = await input.surreal.select<Record<string, unknown>>(entityRecord);
102→      discussedEntity = {
103→        kind: entityRecord.table.name,
104→        name,
105→        ...(row && typeof row.status === "string" ? { status: row.status } : {}),
106→      };
107→    }
108→  }
109→
110→  return {
111→    conversationEntities,
112→    workspaceSummary: {
113→      projects,
114→      recentDecisions,
115→      openQuestions,
116→      openObservations,
117→    },
118→    onboardingSummary,
119→    discussedEntity,
120→  };
121→}
122→
123→function formatConversationEntities(entities: ConversationEntity[]): string {
124→  if (entities.length === 0) {
125→    return "- none";
126→  }
127→
128→  return entities
129→    .slice(0, 20)
130→    .map((entity) => `- ${entity.kind}: ${entity.name} (confidence ${entity.confidence.toFixed(2)})`)
131→    .join("\n");
132→}
133→
134→
135→function formatWorkspaceSummary(context: ChatContext): string {
136→  const { projects, recentDecisions, openQuestions, openObservations } = context.workspaceSummary;
137→
138→  const lines: string[] = [];
139→
140→  // Projects: keep names since they're needed for routing
141→  if (projects.length === 0) {
142→    lines.push("- Projects: none");
143→  } else {
144→    lines.push(`- Projects: ${projects.map((p) => p.name).join(", ")}`);
145→  }
146→
147→  // Decisions: count by status
148→  if (recentDecisions.length === 0) {
149→    lines.push("- Decisions: none");
150→  } else {
151→    const statusCounts = new Map<string, number>();
152→    for (const d of recentDecisions) {
153→      statusCounts.set(d.status, (statusCounts.get(d.status) ?? 0) + 1);
154→    }
155→    const breakdown = [...statusCounts.entries()].map(([s, c]) => `${c} ${s}`).join(", ");
156→    lines.push(`- Decisions: ${recentDecisions.length} (${breakdown})`);
157→  }
158→
159→  // Questions: just count
160→  lines.push(`- Open questions: ${openQuestions.length}`);
161→
162→  // Observations: count by severity
163→  if (openObservations.length === 0) {
164→    lines.push("- Observations: none");
165→  } else {
166→    const severityCounts = new Map<string, number>();
167→    for (const o of openObservations) {
168→      severityCounts.set(o.severity, (severityCounts.get(o.severity) ?? 0) + 1);
169→    }
170→    const breakdown = [...severityCounts.entries()].map(([s, c]) => `${c} ${s}`).join(", ");
171→    lines.push(`- Observations: ${openObservations.length} (${breakdown})`);
172→  }
173→
174→  return lines.join("\n");
175→}
