559→export async function resolveWorkspaceProjectRecord(input: {
560→  surreal: Surreal;
561→  workspaceRecord: RecordId<"workspace", string>;
562→  projectInput: string;
563→}): Promise<RecordId<"project", string>> {
564→  const projectInput = input.projectInput.trim();
565→  if (projectInput.length === 0) {
566→    throw new Error("project identifier is required");
567→  }
568→
569→  if (projectInput.includes(":")) {
570→    const projectRecord = parseRecordIdString(projectInput, ["project"]);
571→    const scoped = await isEntityInWorkspace(input.surreal, input.workspaceRecord, projectRecord);
572→    if (!scoped) {
573→      throw new Error("project is not linked to this workspace");
574→    }
575→    return projectRecord;
576→  }
577→
578→  const projects = await getWorkspaceProjectRows(input.surreal, input.workspaceRecord);
579→  const normalized = normalizeSearchValue(projectInput);
580→
581→  const exactMatch = projects.find((project) => normalizeSearchValue(project.name) === normalized);
582→  if (exactMatch) {
583→    return exactMatch.id;
584→  }
585→
586→  const fuzzyMatches = projects.filter((project) => normalizeSearchValue(project.name).includes(normalized));
587→  if (fuzzyMatches.length === 1) {
588→    return fuzzyMatches[0].id;
589→  }
590→
591→  if (fuzzyMatches.length > 1) {
592→    throw new Error(`project input is ambiguous: ${fuzzyMatches.map((project) => project.name).join(", ")}`);
593→  }
594→
595→  throw new Error(`project not found in workspace: ${projectInput}`);
596→}
