1014→export async function getProjectStatus(input: {
1015→  surreal: Surreal;
1016→  workspaceRecord: RecordId<"workspace", string>;
1017→  projectInput: string;
1018→}): Promise<ProjectStatus> {
1019→  const projectRecord = await resolveWorkspaceProjectRecord({
1020→    surreal: input.surreal,
1021→    workspaceRecord: input.workspaceRecord,
1022→    projectInput: input.projectInput,
1023→  });
1024→
1025→  const project = await input.surreal.select<{ id: RecordId<"project", string>; name: string }>(projectRecord);
1026→  if (!project) {
1027→    throw new Error(`project not found: ${toRecordIdString(projectRecord)}`);
1028→  }
1029→
1030→  const [featureRows] = await input.surreal
1031→    .query<[Array<{ id: RecordId<"feature", string>; name: string; status: string }>]>(
1032→      "SELECT id, name, status FROM feature WHERE id IN (SELECT VALUE out FROM has_feature WHERE `in` = $project);",
1033→      { project: projectRecord },
1034→    )
1035→    .collect<[Array<{ id: RecordId<"feature", string>; name: string; status: string }>]>();
1036→
1037→  const [taskRows] = await input.surreal
1038→    .query<[Array<{ id: RecordId<"task", string>; title: string; status: string; priority?: string; created_at: string | Date }>]>(
1039→      [
1040→        "SELECT id, title, status, priority, created_at",
1041→        "FROM task",
1042→        "WHERE id IN (SELECT VALUE `in` FROM belongs_to WHERE out = $project)",
1043→        "OR id IN (",
1044→        "  SELECT VALUE out",
1045→        "  FROM has_task",
1046→        "  WHERE `in` IN (SELECT VALUE out FROM has_feature WHERE `in` = $project)",
1047→        ")",
1048→        "ORDER BY created_at DESC",
1049→        "LIMIT 100;",
1050→      ].join(" "),
1051→      { project: projectRecord },
1052→    )
1053→    .collect<[Array<{ id: RecordId<"task", string>; title: string; status: string; priority?: string; created_at: string | Date }>]>();
1054→
1055→  const [decisionRows] = await input.surreal
1056→    .query<[Array<{ id: RecordId<"decision", string>; summary: string; status: string; priority?: string; created_at: string | Date }>]>(
1057→      [
1058→        "SELECT id, summary, status, priority, created_at",
1059→        "FROM decision",
1060→        "WHERE id IN (SELECT VALUE `in` FROM belongs_to WHERE out = $project)",
1061→        "ORDER BY created_at DESC",
1062→        "LIMIT 30;",
1063→      ].join(" "),
1064→      { project: projectRecord },
1065→    )
1066→    .collect<[Array<{ id: RecordId<"decision", string>; summary: string; status: string; priority?: string; created_at: string | Date }>]>();
1067→
1068→  const [questionRows] = await input.surreal
1069→    .query<[Array<{ id: RecordId<"question", string>; text: string; status: string; priority?: string; created_at: string | Date }>]>(
1070→      [
1071→        "SELECT id, text, status, priority, created_at",
1072→        "FROM question",
1073→        "WHERE id IN (SELECT VALUE `in` FROM belongs_to WHERE out = $project)",
1074→        "ORDER BY created_at DESC",
1075→        "LIMIT 30;",
1076→      ].join(" "),
1077→      { project: projectRecord },
1078→    )
1079→    .collect<[Array<{ id: RecordId<"question", string>; text: string; status: string; priority?: string; created_at: string | Date }>]>();
1080→
1081→  let active = 0;
1082→  let completed = 0;
1083→  let blocked = 0;
1084→
1085→  for (const task of taskRows) {
1086→    const normalized = task.status.trim().toLowerCase();
1087→    if (normalized === "blocked") {
1088→      blocked += 1;
1089→      continue;
1090→    }
1091→
1092→    if (normalized === "done" || normalized === "completed") {
1093→      completed += 1;
1094→      continue;
1095→    }
1096→
1097→    active += 1;
1098→  }
