 59→export async function loadConversationGraphContext(
 60→  surreal: Surreal,
 61→  conversationId: string,
 62→  limit: number,
 63→  options?: { inheritedEntityIds?: RecordId[] },
 64→): Promise<ExtractionGraphContextRow[]> {
 65→  const conversationRecord = new RecordId("conversation", conversationId);
 66→  const [rows] = await surreal
 67→    .query<[ConversationProvenanceRow[]]>(
 68→      [
 69→        "SELECT `in`, out, confidence, extracted_at",
 70→        "FROM extraction_relation",
 71→        "WHERE `in` IN (SELECT VALUE id FROM message WHERE conversation = $conversation)",
 72→        "ORDER BY extracted_at DESC",
 73→        "LIMIT $limit;",
 74→      ].join(" "),
 75→      { conversation: conversationRecord, limit },
 76→    )
 77→    .collect<[ConversationProvenanceRow[]]>();
 78→
 79→  const seen = new Set<string>();
 80→  const items: ExtractionGraphContextRow[] = [];
 81→
 82→  for (const row of rows) {
 83→    const entityId = row.out.id as string;
 84→    if (seen.has(entityId)) {
 85→      continue;
 86→    }
 87→
 88→    const entityTable = row.out.table.name;
 89→    if (
 90→      entityTable !== "project" &&
 91→      entityTable !== "person" &&
 92→      entityTable !== "feature" &&
 93→      entityTable !== "task" &&
 94→      entityTable !== "decision" &&
 95→      entityTable !== "question"
 96→    ) {
 97→      continue;
 98→    }
 99→
100→    const entityText = await readEntityText(surreal, row.out);
101→    if (!entityText) {
102→      continue;
103→    }
104→
105→    items.push({
106→      id: row.out,
107→      kind: entityTable as ExtractableEntityKind,
108→      text: entityText,
109→      confidence: row.confidence,
110→      sourceMessage: row.in,
111→    });
112→    seen.add(entityId);
113→  }
114→
115→  // Merge inherited entities from parent conversation when branch has sparse context
116→  if (options?.inheritedEntityIds && options.inheritedEntityIds.length > 0 && items.length < 5) {
117→    const [inheritedRows] = await surreal
118→      .query<[ConversationProvenanceRow[]]>(
119→        [
120→          "SELECT `in`, out, confidence, extracted_at",
121→          "FROM extraction_relation",
122→          "WHERE out IN $entityIds",
123→          "ORDER BY extracted_at DESC",
124→          "LIMIT $limit;",
125→        ].join(" "),
126→        { entityIds: options.inheritedEntityIds, limit },
127→      )
128→      .collect<[ConversationProvenanceRow[]]>();
129→
130→    for (const row of inheritedRows) {
131→      const entityId = row.out.id as string;
132→      if (seen.has(entityId)) continue;
133→
134→      const entityTable = row.out.table.name;
135→      if (
136→        entityTable !== "project" &&
137→        entityTable !== "person" &&
138→        entityTable !== "feature" &&
139→        entityTable !== "task" &&
140→        entityTable !== "decision" &&
141→        entityTable !== "question"
142→      ) {
143→        continue;
144→      }
145→
146→      const entityText = await readEntityText(surreal, row.out);
147→      if (!entityText) continue;
148→
149→      items.push({
150→        id: row.out,
151→        kind: entityTable as ExtractableEntityKind,
152→        text: entityText,
153→        confidence: row.confidence,
154→        sourceMessage: row.in,
155→      });
156→      seen.add(entityId);
157→    }
158→  }
159→
160→  return items;
161→}
