17→export function isRicherEntityName(incomingName: string, existingName: string): boolean {
18→  const normalizedIncoming = normalizeName(incomingName);
19→  const normalizedExisting = normalizeName(existingName);
20→  if (normalizedIncoming.length === 0 || normalizedExisting.length === 0) {
21→    return false;
22→  }
23→
24→  const incomingWords = normalizedIncoming.split(" ").filter((word) => word.length > 0);
25→  const existingWords = normalizedExisting.split(" ").filter((word) => word.length > 0);
26→  if (incomingWords.length <= existingWords.length) {
27→    return false;
28→  }
29→
30→  return normalizedIncoming.length > normalizedExisting.length;
31→}
32→
33→export function pickRicherEntityName(incomingName: string, existingName: string): string {
34→  return isRicherEntityName(incomingName, existingName) ? incomingName : existingName;
35→}
